use std::collections::VecDeque;

struct Interpreter<T> {
    input_queue: VecDeque<T>,
}

impl<T: std::fmt::Debug + Clone> Interpreter<T> {
    fn new(initial_inputs: Vec<T>) -> Self {
        Interpreter { 
            input_queue: initial_inputs.into()
        }
    }

    fn process_next(&mut self) -> Option<T> {
        self.input_queue.pop_front()
    }

    fn is_empty(&self) -> bool {
        self.input_queue.is_empty()
    }
}

fn main() {
    let mut interpreter = Interpreter::new(vec![10i32, 5i32]);

    if let Some(result1) = interpreter.process_next() {
        println!("First item processed: {:?}", result1);
    }

    if let Some(result2) = interpreter.process_next() {
        println!("Second item processed: {:?}", result2);
    }

    if interpreter.is_empty() {
        println!("Interpreter queue is now empty.");
    }
}
